/* eslint-disable */

import puppeteer from 'puppeteer';
import * as chromeLauncher from 'chrome-launcher';
import lighthouse, {navigation, snapshot, generateReport} from '../dist/lighthouse-devtools-mcp-bundle.js';

async function main() {
  console.log('Lighthouse MCP Bundle Loaded Successfully');

  const url = 'https://example.com';

  console.log('Launching browser via chrome-launcher...');
  const chrome = await chromeLauncher.launch({chromeFlags: ['--headless']});

  console.log(`Connecting Puppeteer to port ${chrome.port}...`);
  const resp = await fetch(`http://localhost:${chrome.port}/json/version`);
  const {webSocketDebuggerUrl} = await resp.json();
  const browser = await puppeteer.connect({browserWSEndpoint: webSocketDebuggerUrl});

  const page = (await browser.pages())[0];

  console.log(`Running Lighthouse on ${url}...`);
  const options = {
    output: 'json',
    onlyCategories: ['accessibility'],
    throttlingMethod: 'provided',
    logLevel: 'info',
  };

  try {
    const result = await lighthouse(url, options, undefined, page);

    if (result && result.lhr) {
      const {lhr} = result;
      console.log('LHR generated successfully!');
      console.log('URL:', lhr.requestedUrl);
      console.log('Accessibility Score:', lhr.categories.accessibility?.score);

      const accessibilityAudits = Object.values(lhr.audits).filter(a => a.id.includes('accessibility') || (lhr.categories.accessibility.auditRefs.some(ref => ref.id === a.id)));
      const passedCount = accessibilityAudits.filter(a => a.score === 1).length;
      const failedCount = accessibilityAudits.filter(a => a.score === 0).length;

      console.log(`Passed Accessibility Audits: ${passedCount}`);
      console.log(`Failed Accessibility Audits: ${failedCount}`);

      if (lhr.categories.accessibility?.score !== null) {
        console.log('SUCCESS: MCP bundle successfully executed accessibility audits.');
      } else {
        console.error('FAILURE: Accessibility score is null.');
      }
    } else {
      console.error('FAILURE: No LHR returned.');
    }
  } catch (err) {
    console.error('Lighthouse execution failed:', err);
    process.exit(1);
  } finally {
    if (browser) await browser.disconnect();
    if (chrome) await chrome.kill();
  }
}

main().catch(console.error);
